  1→import { useEffect, useRef } from "react";
  2→import {
  3→  Chat,
  4→  ChatSuggestions,
  5→  ChatInput,
  6→  SessionMessage,
  7→  SessionMessagePanel,
  8→  SessionMessages,
  9→  type SlashCommandItem,
 10→} from "reachat";
 11→import { chatComponentCatalog } from "../chat-component-catalog";
 12→import { darkChatTheme } from "../chat-theme";
 13→import { DiscussEntityCard } from "../components/chat/DiscussEntityCard";
 14→import type { DiscussEntitySummary } from "../../shared/contracts";
 15→import { useWorkspaceState } from "../stores/workspace-state";
 16→import { useChatSession } from "../hooks/use-chat-session";
 17→import { entityLinkMarkdownComponents } from "../components/chat/EntityLink";
 18→
 19→const COMMAND_ITEMS: SlashCommandItem[] = [
 20→  {
 21→    id: "task",
 22→    label: "task",
 23→    description: "Record a task",
 24→    type: "insert",
 25→    value: "task: ",
 26→  },
 27→  {
 28→    id: "decision",
 29→    label: "decision",
 30→    description: "Record a decision",
 31→    type: "insert",
 32→    value: "decision: ",
 33→  },
 34→  {
 35→    id: "question",
 36→    label: "question",
 37→    description: "Record an open question",
 38→    type: "insert",
 39→    value: "question: ",
 40→  },
 41→];
 42→
 43→export function ChatPage() {
 44→  const onboardingState = useWorkspaceState((s) => s.onboardingState);
 45→  const setSidebarHandlers = useWorkspaceState((s) => s.setSidebarHandlers);
 46→
 47→  const chat = useChatSession();
 48→
 49→  // Keep a ref to the latest chat handlers so the effect below doesn't
 50→  // depend on unstable function references (which would cause an infinite
 51→  // render loop: new fn refs → effect fires → setSidebarHandlers → zustand
 52→  // update → AppShell re-renders → ChatPage re-renders → new fn refs → …).
 53→  const chatRef = useRef(chat);
 54→  chatRef.current = chat;
 55→
 56→  // Register sidebar handlers so the shell sidebar can interact with chat
 57→  useEffect(() => {
 58→    setSidebarHandlers({
 59→      activeConversationId: chat.activeConversationId,
 60→      isLoading: chat.isLoading,
 61→      onNewConversation: () => chatRef.current.onNewConversation(),
 62→      onSelectConversation: (id: string) => chatRef.current.onSelectConversation(id),
 63→    });
 64→  }, [chat.activeConversationId, chat.isLoading]);
 65→
 66→  // Cleanup sidebar handlers on unmount
 67→  useEffect(() => {
 68→    return () => {
 69→      setSidebarHandlers(undefined);
 70→    };
 71→  }, []);
 72→
 73→  return (
 74→    <section className="reachat-page">
 75→      {chat.pendingFile ? (
 76→        <div className="workspace-toolbar">
 77→          <div className="pending-file">
 78→            Attached: {chat.pendingFile.name}
 79→            <button type="button" onClick={() => chat.onUploadFile(undefined as unknown as File)}>
 80→              Clear
 81→            </button>
 82→          </div>
 83→        </div>
 84→      ) : undefined}
 85→
 86→      {(chat.discussEntity ?? chat.conversationDiscussEntity) ? (
 87→        <DiscussEntityCard
 88→          entity={(chat.discussEntity ?? chat.conversationDiscussEntity) as DiscussEntitySummary}
 89→        />
 90→      ) : undefined}
 91→
 92→      <div className="chat-main">
 93→        <Chat
 94→          viewType="chat"
 95→          theme={darkChatTheme}
 96→          sessions={chat.sessions}
 97→          activeSessionId={chat.activeSession.id}
 98→          components={chatComponentCatalog}
 99→          markdownComponents={entityLinkMarkdownComponents}
100→          isLoading={chat.isLoading}
101→          onSendMessage={chat.onSendMessage}
102→          onStopMessage={chat.onStopMessage}
103→          onFileUpload={chat.onUploadFile}
104→        >
105→          <SessionMessagePanel>
106→            <SessionMessages>
107→              {(conversations) =>
108→                conversations.map((conversation, index) => {
109→                  const isInherited = chat.inheritedMessageIds.has(conversation.id);
110→                  const isLastInherited = isInherited
111→                    && index < conversations.length - 1
112→                    && !chat.inheritedMessageIds.has(conversations[index + 1].id);
113→                  return (
114→                    <div
115→                      key={conversation.id}
116→                      data-message-id={conversation.id}
117→                      className={isInherited ? "message-inherited" : undefined}
118→                    >
119→                      <SessionMessage
120→                        conversation={conversation}
121→                        isLast={index === conversations.length - 1}
122→                      />
123→                      {!isInherited && conversation.response && onboardingState === "complete" ? (
124→                        <button
125→                          type="button"
126→                          className="branch-message-btn"
127→                          onClick={() => void chat.onBranchFromMessage(conversation.id)}
128→                          disabled={chat.isLoading || chat.branchingFromId !== undefined}
129→                          title="Branch from here"
130→                        >
131→                          <svg width="16" height="16" viewBox="0 0 16 16" fill="none" xmlns="http://www.w3.org/2000/svg" aria-hidden="true">
132→                            <path d="M5 3v4.5c0 1.1.9 2 2 2h2.5M5 3L3 5M5 3l2 2M11 5v4.5c0 1.1-.9 2-2 2H6.5M11 5l-2-2M11 5l2-2" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"/>
133→                          </svg>
134→                        </button>
135→                      ) : undefined}
136→                      {isLastInherited ? (
137→                        <div className="branch-divider">Branch point</div>
138→                      ) : undefined}
139→                    </div>
140→                  );
141→                })
142→              }
143→            </SessionMessages>
144→            <ChatSuggestions
145→              suggestions={chat.suggestions}
146→              onSuggestionClick={(suggestion) => {
147→                void chat.onSendMessage(suggestion);
148→              }}
149→            />
150→            {onboardingState === "summary_pending" ? (
151→              <div className="onboarding-action-buttons">
152→                <button
153→                  type="button"
154→                  disabled={chat.isLoading}
155→                  onClick={() =>
156→                    void chat.onSendMessage("Looks good, let's go.", {
157→                      onboardingAction: "finalize_onboarding",
158→                    })}
159→                >
160→                  Looks good, let's go
161→                </button>
162→                <button
163→                  type="button"
164→                  disabled={chat.isLoading}
165→                  onClick={() =>
166→                    void chat.onSendMessage("I want to add more.", {
167→                      onboardingAction: "continue_onboarding",
168→                    })}
169→                >
170→                  I want to add more
171→                </button>
172→              </div>
173→            ) : undefined}
174→            <div onClickCapture={chat.onChatInputClickCapture}>
175→              <ChatInput
176→                ref={chat.chatInputRef}
177→                placeholder="Discuss tasks, decisions, and questions..."
178→                allowedFiles={[".md", ".txt"]}
179→                mentions={{
180→                  onSearch: chat.searchMentions,
181→                }}
182→                commands={{
183→                  items: COMMAND_ITEMS,
184→                }}
185→              />
186→            </div>
187→          </SessionMessagePanel>
188→        </Chat>
189→
190→      </div>
191→
192→      {chat.errorMessage ? <p className="error-message">{chat.errorMessage}</p> : undefined}
193→    </section>
194→  );
195→}
