  1→import { useState } from "react";
  2→import { Outlet, createRootRoute, createRoute, createRouter, useNavigate } from "@tanstack/react-router";
  3→import { WorkspaceGuard } from "./components/layout/WorkspaceGuard";
  4→import { WorkspaceSidebar } from "./components/layout/WorkspaceSidebar";
  5→import { SearchOverlay } from "./components/search/SearchOverlay";
  6→import { useWorkspace } from "./hooks/use-workspace";
  7→import { useWorkspaceState } from "./stores/workspace-state";
  8→import { ChatPage } from "./routes/chat-page";
  9→import { GraphPage } from "./routes/graph-page";
 10→import { HomePage } from "./routes/home-page";
 11→
 12→function AppShell() {
 13→  const workspace = useWorkspace();
 14→  const sidebar = useWorkspaceState((s) => s.sidebar);
 15→  const sidebarHandlers = useWorkspaceState((s) => s.sidebarHandlers);
 16→  const workspaceName = useWorkspaceState((s) => s.workspaceName);
 17→  const navigate = useNavigate();
 18→  const [searchOpen, setSearchOpen] = useState(false);
 19→
 20→  function handleNewConversation() {
 21→    if (sidebarHandlers) {
 22→      sidebarHandlers.onNewConversation();
 23→    }
 24→    void navigate({ to: "/chat" });
 25→  }
 26→
 27→  function handleSelectConversation(conversationId: string) {
 28→    if (sidebarHandlers) {
 29→      sidebarHandlers.onSelectConversation(conversationId);
 30→    }
 31→    void navigate({ to: "/chat" });
 32→  }
 33→
 34→  return (
 35→    <WorkspaceGuard
 36→      isReady={workspace.isReady}
 37→      isBootstrapping={workspace.isBootstrapping}
 38→      isCreatingWorkspace={workspace.isCreatingWorkspace}
 39→      canCreateWorkspace={workspace.canCreateWorkspace}
 40→      createWorkspaceName={workspace.createWorkspaceName}
 41→      createOwnerName={workspace.createOwnerName}
 42→      errorMessage={workspace.errorMessage}
 43→      setCreateWorkspaceName={workspace.setCreateWorkspaceName}
 44→      setCreateOwnerName={workspace.setCreateOwnerName}
 45→      onCreateWorkspace={workspace.onCreateWorkspace}
 46→    >
 47→      <div className="app-shell">
 48→        <WorkspaceSidebar
 49→          sidebar={sidebar}
 50→          activeConversationId={sidebarHandlers?.activeConversationId}
 51→          isLoading={sidebarHandlers?.isLoading ?? false}
 52→          onNewConversation={handleNewConversation}
 53→          onSelectConversation={handleSelectConversation}
 54→        />
 55→        <div className="app-main">
 56→          <div className="content-header">
 57→            <span className="content-header-title">{workspaceName}</span>
 58→            <button
 59→              type="button"
 60→              className="search-trigger"
 61→              onClick={() => setSearchOpen(true)}
 62→            >
 63→              Search...
 64→            </button>
 65→          </div>
 66→          <div className="app-content">
 67→            <Outlet />
 68→          </div>
 69→        </div>
 70→      </div>
 71→      {searchOpen ? <SearchOverlay onClose={() => setSearchOpen(false)} /> : undefined}
 72→    </WorkspaceGuard>
 73→  );
 74→}
 75→
 76→const rootRoute = createRootRoute({
 77→  component: AppShell,
 78→});
 79→
 80→const homeRoute = createRoute({
 81→  getParentRoute: () => rootRoute,
 82→  path: "/",
 83→  component: HomePage,
 84→});
 85→
 86→const chatRoute = createRoute({
 87→  getParentRoute: () => rootRoute,
 88→  path: "/chat",
 89→  component: ChatPage,
 90→});
 91→
 92→const graphRoute = createRoute({
 93→  getParentRoute: () => rootRoute,
 94→  path: "/graph",
 95→  component: GraphPage,
 96→});
 97→
 98→const routeTree = rootRoute.addChildren([homeRoute, chatRoute, graphRoute]);
 99→
100→export const router = createRouter({ routeTree });
101→
102→declare module "@tanstack/react-router" {
103→  interface Register {
104→    router: typeof router;
105→  }
106→}
