173→async function handleWorkspaceBootstrap(deps: ServerDependencies, workspaceId: string): Promise<Response> {
174→  const startedAt = performance.now();
175→  logInfo("workspace.bootstrap.started", "Workspace bootstrap started", { workspaceId });
176→
177→  try {
178→    const workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
179→    const workspace = await deps.surreal.select<WorkspaceRow>(workspaceRecord);
180→    if (!workspace) {
181→      throw new HttpError(404, `workspace not found: ${workspaceId}`);
182→    }
183→
184→    const conversationRecord = await resolveWorkspaceBootstrapConversation(deps, workspaceRecord);
185→    const conversationId = conversationRecord.id as string;
186→    const rawMessages = await loadMessagesWithInheritance(deps.surreal, conversationId, 80);
187→
188→    const messages = rawMessages.map((row) => ({
189→      id: row.id,
190→      role: row.role,
191→      text: row.text,
192→      createdAt: toIsoString(row.createdAt),
193→      ...(row.suggestions && row.suggestions.length > 0 ? { suggestions: row.suggestions } : {}),
194→      ...(row.inherited ? { inherited: true } : {}),
195→    } satisfies WorkspaceBootstrapMessage));
196→
197→    const seeds = await loadWorkspaceSeeds(deps, workspaceRecord, 40);
198→    const onboardingState = toOnboardingState(workspace);
199→    const sidebar = await buildWorkspaceConversationSidebar(deps.surreal, workspaceRecord);
200→
201→    const payload: WorkspaceBootstrapResponse = {
202→      workspaceId: workspace.id.id as string,
203→      workspaceName: workspace.name,
204→      onboardingComplete: workspace.onboarding_complete,
205→      onboardingState,
206→      conversationId: conversationRecord.id as string,
207→      messages,
208→      seeds,
209→      sidebar,
210→    };
211→
212→    logInfo("workspace.bootstrap.completed", "Workspace bootstrap completed", {
213→      workspaceId,
214→      conversationId: conversationRecord.id as string,
215→      messageCount: messages.length,
216→      seedCount: seeds.length,
217→      durationMs: elapsedMs(startedAt),
218→    });
219→
220→    return jsonResponse(payload, 200);
221→  } catch (error) {
222→    if (error instanceof HttpError) {
223→      logWarn("workspace.bootstrap.http_error", "Workspace bootstrap failed with client-facing error", {
224→        workspaceId,
225→        statusCode: error.status,
226→      });
227→      return jsonError(error.message, error.status);
228→    }
229→
230→    logError("workspace.bootstrap.failed", "Workspace bootstrap failed", error, { workspaceId });
231→    const errorText = error instanceof Error ? error.message : "workspace bootstrap failed";
232→    return jsonError(errorText, 500);
233→  }
234→}
